fn ir_list_has_derived_list_view(ir: &TypedProgram, list_name: &str) -> bool {
    let store_path = format!("store.{list_name}");
    ir.derived_values.iter().any(|value| {
        matches!(value.kind, DerivedValueKind::ListView)
            && (value.path == list_name
                || value.path == store_path
                || row_field_name(&value.path) == list_name)
    })
}

fn list_initial_records_have_dynamic_fields(rows: &[ListInitialRecord]) -> bool {
    rows.iter().any(|row| {
        row.fields
            .iter()
            .any(|field| matches!(field.value, InitialValue::Unknown { .. }))
    })
}

fn dynamic_list_view_lists_from_ir(ir: &TypedProgram) -> BTreeSet<String> {
    ir.lists
        .iter()
        .filter(|list| ir_list_has_derived_list_view(ir, &list.name))
        .map(|list| list.name.clone())
        .collect()
}

fn derived_root_list_storage_name(path: &str) -> String {
    path.strip_prefix("store.")
        .map(str::to_owned)
        .unwrap_or_else(|| row_field_name(path).to_owned())
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
struct TypedStorageLayoutCounts {
    root_text_slot_count: usize,
    root_bool_slot_count: usize,
    root_enum_slot_count: usize,
    list_memory_count: usize,
    list_row_template_field_count: usize,
    list_row_text_slot_count: usize,
    list_row_bool_slot_count: usize,
    list_row_enum_slot_count: usize,
    list_hidden_key_slot_count: usize,
    list_hidden_generation_slot_count: usize,
}

impl TypedStorageLayoutCounts {
    fn from_ir(ir: &TypedProgram) -> Self {
        let mut counts = Self {
            list_memory_count: ir.lists.len(),
            list_hidden_key_slot_count: ir.lists.len(),
            list_hidden_generation_slot_count: ir.lists.len(),
            ..Self::default()
        };
        for cell in &ir.state_cells {
            match (cell.indexed, &cell.initial_value) {
                (false, InitialValue::Bool { .. }) => counts.root_bool_slot_count += 1,
                (false, InitialValue::Enum { .. }) => counts.root_enum_slot_count += 1,
                (
                    false,
                    InitialValue::Text { .. }
                    | InitialValue::Number { .. }
                    | InitialValue::RootInitialField { .. }
                    | InitialValue::RowInitialField { .. },
                ) => {
                    counts.root_text_slot_count += 1;
                }
                (false, InitialValue::Unknown { .. }) => {}
                (true, InitialValue::Bool { .. }) => {
                    counts.list_row_template_field_count += 1;
                    counts.list_row_bool_slot_count += 1;
                }
                (true, InitialValue::Enum { .. }) => {
                    counts.list_row_template_field_count += 1;
                    counts.list_row_enum_slot_count += 1;
                }
                (
                    true,
                    InitialValue::Text { .. }
                    | InitialValue::Number { .. }
                    | InitialValue::RootInitialField { .. }
                    | InitialValue::RowInitialField { .. },
                ) => {
                    counts.list_row_template_field_count += 1;
                    counts.list_row_text_slot_count += 1;
                }
                (true, InitialValue::Unknown { .. }) => {}
            }
        }
        counts.list_row_text_slot_count += ir
            .derived_values
            .iter()
            .filter(|value| value.indexed)
            .count();
        counts
    }
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
struct SourcePayloadCounts {
    schema_count: usize,
    field_count: usize,
    text_field_count: usize,
    key_field_count: usize,
    address_field_count: usize,
    pointer_field_count: usize,
}

impl SourcePayloadCounts {
    fn from_ir(ir: &TypedProgram) -> Self {
        let mut counts = Self {
            schema_count: ir.sources.len(),
            ..Self::default()
        };
        for source in &ir.sources {
            for field in &source.payload_schema.fields {
                counts.field_count += 1;
                match field {
                    SourcePayloadField::Text => counts.text_field_count += 1,
                    SourcePayloadField::Key => counts.key_field_count += 1,
                    SourcePayloadField::Address => counts.address_field_count += 1,
                    SourcePayloadField::Named(_) => counts.pointer_field_count += 1,
                }
            }
        }
        counts
    }
}

fn list_summary_fields_from_ir(ir: &TypedProgram) -> Vec<ListSummaryFields> {
    let mut summaries = ir
        .lists
        .iter()
        .map(|list| {
            let row_scope = row_scope_name_for_ir_list(ir, list);
            let prefix = format!("{row_scope}.");
            let mut fields = ir
                .state_cells
                .iter()
                .filter(|cell| cell.indexed && cell.path.starts_with(&prefix))
                .map(|cell| row_field_name(&cell.path).to_owned())
                .collect::<Vec<_>>();
            for value in &ir.derived_values {
                if value.indexed && value.path.starts_with(&prefix) {
                    fields.push(row_field_name(&value.path).to_owned());
                }
            }
            if let boon_ir::ListInitializer::RecordLiteral { rows } = &list.initializer {
                for row in rows {
                    for field in &row.fields {
                        fields.push(field.name.clone());
                    }
                }
            }
            for operation in &ir.list_operations {
                let ListOperationKind::Append {
                    fields: append_fields,
                    ..
                } = &operation.kind
                else {
                    continue;
                };
                if operation.list == list.name {
                    fields.extend(append_fields.iter().map(|field| field.name.clone()));
                }
            }
            fields.sort();
            fields.dedup();
            ListSummaryFields {
                list: list.name.clone(),
                row_scope,
                fields,
            }
        })
        .collect::<Vec<_>>();
    for value in ir.derived_values.iter().filter(|value| {
        !value.indexed
            && value.scope_id.is_none()
            && matches!(value.kind, DerivedValueKind::ListView)
    }) {
        let list = derived_root_list_storage_name(&value.path);
        if summaries.iter().any(|summary| summary.list == list) {
            continue;
        }
        summaries.push(ListSummaryFields {
            row_scope: list.clone(),
            list,
            fields: Vec::new(),
        });
    }
    summaries
}

fn list_operation_has_unknown_predicate(operation: &boon_ir::ListOperation) -> bool {
    match &operation.kind {
        ListOperationKind::Append { .. } => false,
        ListOperationKind::Remove { predicate, .. }
        | ListOperationKind::Retain { predicate, .. }
        | ListOperationKind::Count { predicate, .. } => {
            matches!(predicate, ListPredicate::Unknown { .. })
        }
    }
}

struct StepExecutionMetrics {
    dirty_key_count: usize,
    extra: StepExecutionExtra,
}

impl StepExecutionMetrics {
    fn runtime_step_profile(&self) -> LiveRuntimeStepProfile {
        match &self.extra {
            StepExecutionExtra::Generic {
                runtime_step_profile,
                ..
            } => runtime_step_profile.clone(),
        }
    }

    fn recomputed_field_count(&self) -> usize {
        match self.extra {
            StepExecutionExtra::Generic {
                recomputed_field_count,
                ..
            } => recomputed_field_count,
        }
    }

    fn recompute_candidate_count(&self) -> usize {
        match self.extra {
            StepExecutionExtra::Generic {
                recompute_candidate_count,
                ..
            } => recompute_candidate_count,
        }
    }

    fn recompute_candidate_samples(&self) -> Vec<String> {
        match &self.extra {
            StepExecutionExtra::Generic {
                recompute_candidate_samples,
                ..
            } => recompute_candidate_samples.clone(),
        }
    }

    fn recomputed_field_samples(&self) -> Vec<String> {
        match &self.extra {
            StepExecutionExtra::Generic {
                recomputed_field_samples,
                ..
            } => recomputed_field_samples.clone(),
        }
    }

    fn route_actions_visited(&self) -> usize {
        match self.extra {
            StepExecutionExtra::Generic {
                route_actions_visited,
                ..
            } => route_actions_visited,
        }
    }

    fn row_touched_count(&self) -> usize {
        match self.extra {
            StepExecutionExtra::Generic {
                row_touched_count, ..
            } => row_touched_count,
        }
    }

    fn list_scan_counters(&self) -> RuntimeListScanCounters {
        match self.extra {
            StepExecutionExtra::Generic {
                list_scan_counters, ..
            } => list_scan_counters,
        }
    }

    fn source_route_scan_summary(&self) -> LiveRuntimeSourceRouteScanSummary {
        match &self.extra {
            StepExecutionExtra::Generic {
                route_execution, ..
            } => route_execution
                .as_ref()
                .map(SourceRouteExecutionStats::scan_summary)
                .unwrap_or_default(),
        }
    }

    fn root_materialization_stats(&self) -> LiveRuntimeRootMaterializationStats {
        match &self.extra {
            StepExecutionExtra::Generic {
                root_materialization_stats,
                ..
            } => root_materialization_stats.clone(),
        }
    }

    fn function_call_stats(&self) -> LiveRuntimeFunctionCallStats {
        match &self.extra {
            StepExecutionExtra::Generic {
                function_call_stats,
                ..
            } => function_call_stats.clone(),
        }
    }

    fn list_delta_counters(&self) -> RuntimeListDeltaCounters {
        match self.extra {
            StepExecutionExtra::Generic {
                list_delta_counters,
                ..
            } => list_delta_counters,
        }
    }

    fn dirty_set_metrics(&self) -> RuntimeDirtySetMetrics {
        match &self.extra {
            StepExecutionExtra::Generic {
                dirty_set_metrics, ..
            } => dirty_set_metrics.clone(),
        }
    }

    fn route_execution_report(
        &self,
        allocation_count: u64,
        allocation_bytes: u64,
    ) -> Option<JsonValue> {
        match &self.extra {
            StepExecutionExtra::Generic {
                recompute_candidate_count,
                route_execution,
                list_scan_counters,
                list_delta_counters,
                dirty_set_metrics,
                ..
            } => route_execution.as_ref().map(|execution| {
                let mut report = execution.to_report(
                    self.dirty_key_count,
                    *recompute_candidate_count,
                    allocation_count,
                    allocation_bytes,
                );
                if let Some(object) = report.as_object_mut() {
                    object.insert(
                        "list_scan_counters".to_owned(),
                        list_scan_counters.to_report(),
                    );
                    object.insert(
                        "list_delta_counters".to_owned(),
                        list_delta_counters.to_report(),
                    );
                    object.insert(
                        "dirty_set_metrics".to_owned(),
                        dirty_set_metrics.to_report(),
                    );
                }
                report
            }),
        }
    }
}

