    fn list_row_field_names(&self, list: &str, index: usize) -> RuntimeResult<Vec<String>> {
        self.lists
            .memory(list)
            .ok_or_else(|| format!("generic runtime has no list `{list}`"))?
            .field_names(index)
            .ok_or_else(|| format!("generic list `{list}` has no row {index}").into())
    }

