fn list_read_key(list: &str) -> GenericReadKey {
    GenericReadKey::List {
        list: list.to_owned(),
    }
}

fn list_column_read_key(list: &str, field: &str) -> GenericReadKey {
    GenericReadKey::ListColumn {
        list: list.to_owned(),
        field: field.to_owned(),
    }
}

fn generic_read_key_list(read: &GenericReadKey) -> Option<&str> {
    match read {
        GenericReadKey::List { list }
        | GenericReadKey::ListColumn { list, .. }
        | GenericReadKey::ListField { list, .. } => Some(list),
        GenericReadKey::Root { .. } => None,
    }
}

fn generic_read_key_kind_counts(reads: &BTreeSet<GenericReadKey>) -> (usize, usize, usize, usize) {
    let mut root_count = 0usize;
    let mut list_count = 0usize;
    let mut list_column_count = 0usize;
    let mut list_field_count = 0usize;
    for read in reads {
        match read {
            GenericReadKey::Root { .. } => root_count = root_count.saturating_add(1),
            GenericReadKey::List { .. } => list_count = list_count.saturating_add(1),
            GenericReadKey::ListColumn { .. } => {
                list_column_count = list_column_count.saturating_add(1);
            }
            GenericReadKey::ListField { .. } => {
                list_field_count = list_field_count.saturating_add(1);
            }
        }
    }
    (root_count, list_count, list_column_count, list_field_count)
}

fn generic_read_key_kind_label(read: &GenericReadKey) -> &'static str {
    match read {
        GenericReadKey::Root { .. } => "root",
        GenericReadKey::List { .. } => "list",
        GenericReadKey::ListColumn { .. } => "list_column",
        GenericReadKey::ListField { .. } => "list_field",
    }
}

fn generic_read_key_label(read: &GenericReadKey) -> String {
    match read {
        GenericReadKey::Root { field } => format!("root:{field}"),
        GenericReadKey::List { list } => format!("list:{list}"),
        GenericReadKey::ListColumn { list, field } => {
            format!("list_column:{list}.{field}")
        }
        GenericReadKey::ListField { list, index, field } => {
            format!("list_field:{list}[{index}].{field}")
        }
    }
}

fn record_dirty_frontier_cause(
    accumulators: &mut BTreeMap<RuntimeDirtyFrontierCauseKey, RuntimeDirtyFrontierCauseAccumulator>,
    source_changed_root: Option<&str>,
    read: &GenericReadKey,
    dependent_root: &str,
    dependent_kind: &str,
    enqueued: bool,
    already_dirty: bool,
    skipped_self: bool,
    structured_parent_skip: bool,
) {
    let entry = accumulators
        .entry(RuntimeDirtyFrontierCauseKey {
            source_changed_root: source_changed_root.map(str::to_owned),
            read_key: generic_read_key_label(read),
            read_key_kind: generic_read_key_kind_label(read).to_owned(),
            dependent_root: dependent_root.to_owned(),
            dependent_kind: dependent_kind.to_owned(),
        })
        .or_default();
    entry.dependency_lookup_count = entry.dependency_lookup_count.saturating_add(1);
    entry.dependent_visit_count = entry.dependent_visit_count.saturating_add(1);
    if enqueued {
        entry.dependent_enqueue_count = entry.dependent_enqueue_count.saturating_add(1);
    }
    if already_dirty {
        entry.already_dirty_count = entry.already_dirty_count.saturating_add(1);
    }
    if skipped_self {
        entry.skipped_self_count = entry.skipped_self_count.saturating_add(1);
    }
    if structured_parent_skip {
        entry.structured_parent_skip_count = entry.structured_parent_skip_count.saturating_add(1);
    }
}

fn dirty_frontier_cause_samples(
    accumulators: BTreeMap<RuntimeDirtyFrontierCauseKey, RuntimeDirtyFrontierCauseAccumulator>,
) -> Vec<LiveRuntimeDirtyFrontierCauseSample> {
    let mut samples = accumulators
        .into_iter()
        .map(|(key, value)| LiveRuntimeDirtyFrontierCauseSample {
            source_changed_root: key.source_changed_root,
            read_key: key.read_key,
            read_key_kind: key.read_key_kind,
            dependent_root: key.dependent_root,
            dependent_kind: key.dependent_kind,
            dependency_lookup_count: value.dependency_lookup_count,
            dependent_visit_count: value.dependent_visit_count,
            dependent_enqueue_count: value.dependent_enqueue_count,
            already_dirty_count: value.already_dirty_count,
            skipped_self_count: value.skipped_self_count,
            structured_parent_skip_count: value.structured_parent_skip_count,
        })
        .collect::<Vec<_>>();
    samples.sort_by(|left, right| {
        right
            .dependent_enqueue_count
            .cmp(&left.dependent_enqueue_count)
            .then_with(|| right.dependent_visit_count.cmp(&left.dependent_visit_count))
            .then_with(|| right.already_dirty_count.cmp(&left.already_dirty_count))
            .then_with(|| left.read_key.cmp(&right.read_key))
            .then_with(|| left.dependent_root.cmp(&right.dependent_root))
    });
    samples.truncate(LIVE_RUNTIME_DIRTY_FRONTIER_SAMPLE_LIMIT);
    samples
}

fn dirty_root_work_samples(
    accumulators: BTreeMap<String, RuntimeDirtyRootWorkAccumulator>,
) -> Vec<LiveRuntimeDirtyRootWorkSample> {
    let mut samples = accumulators
        .into_iter()
        .map(|(root_path, value)| LiveRuntimeDirtyRootWorkSample {
            root_path,
            root_kind: value.root_kind,
            pop_count: value.pop_count,
            skip_count: value.skip_count,
            scalar_materialization_count: value.scalar_materialization_count,
            list_view_materialization_count: value.list_view_materialization_count,
            changed_materialization_count: value.changed_materialization_count,
            unchanged_materialization_count: value.unchanged_materialization_count,
            changed_read_count: value.changed_read_count,
            materialization_ms: value.materialization_ms,
        })
        .collect::<Vec<_>>();
    samples.sort_by(|left, right| {
        right
            .materialization_ms
            .partial_cmp(&left.materialization_ms)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| right.pop_count.cmp(&left.pop_count))
            .then_with(|| left.root_path.cmp(&right.root_path))
    });
    samples.truncate(LIVE_RUNTIME_DIRTY_ROOT_WORK_SAMPLE_LIMIT);
    samples
}

fn cache_entry_invalidated_by_reads(
    cached_reads: &BTreeSet<GenericReadKey>,
    numeric_stability_guards: &BTreeMap<GenericReadKey, NumericStabilityInterval>,
    changed_reads: &BTreeSet<GenericReadKey>,
    root_numbers: &BTreeMap<String, i64>,
) -> bool {
    if cached_reads.is_empty() || changed_reads.is_empty() {
        return false;
    }
    let direct_overlaps = cached_reads.intersection(changed_reads).collect::<Vec<_>>();
    if !direct_overlaps.is_empty() {
        return direct_overlaps.into_iter().any(|read| {
            let GenericReadKey::Root { field } = read else {
                return true;
            };
            let Some(interval) = numeric_stability_guards.get(read).copied() else {
                return true;
            };
            !root_numbers
                .get(field)
                .is_some_and(|value| interval.contains(*value))
        });
    }
    let changed_lists = changed_reads
        .iter()
        .filter_map(|read| match read {
            GenericReadKey::List { list } => Some(list.as_str()),
            _ => None,
        })
        .collect::<BTreeSet<_>>();
    !changed_lists.is_empty()
        && cached_reads.iter().any(|read| {
            generic_read_key_list(read).is_some_and(|list| changed_lists.contains(list))
        })
}

fn homogeneous_row_ref_list(values: &[BoonValue]) -> Option<&str> {
    let mut values = values.iter();
    let BoonValue::RowRef { list, .. } = values.next()? else {
        return None;
    };
    values
        .all(
            |value| matches!(value, BoonValue::RowRef { list: candidate, .. } if candidate == list),
        )
        .then_some(list.as_str())
}

fn insert_changed_list_field_read_keys(
    reads: &mut BTreeSet<GenericReadKey>,
    list: &str,
    index: usize,
    field: &str,
) {
    reads.insert(list_column_read_key(list, field));
    reads.insert(GenericReadKey::ListField {
        list: list.to_owned(),
        index,
        field: field.to_owned(),
    });
}

fn sort_root_scalar_targets_for_same_event_reads(targets: &mut Vec<SourceRouteScalarTarget>) {
    targets.sort_by_key(|target| target.expression.prefers_settled_root_derived_reads());
    let target_paths = targets
        .iter()
        .map(|target| target.target.clone())
        .collect::<Vec<_>>();
    let mut pending = std::mem::take(targets);
    let mut sorted = Vec::with_capacity(pending.len());
    let mut settled = BTreeSet::new();
    while !pending.is_empty() {
        let ready_position = pending.iter().position(|candidate| {
            candidate
                .expression
                .same_event_root_read_paths()
                .iter()
                .all(|read| {
                    let dependency = target_paths.iter().find(|target| {
                        target.as_str() != candidate.target && root_scalar_paths_match(read, target)
                    });
                    dependency.is_none_or(|target| settled.contains(target))
                })
        });
        let next = pending.remove(ready_position.unwrap_or(0));
        settled.insert(next.target.clone());
        sorted.push(next);
    }
    *targets = sorted;
}

fn root_scalar_paths_match(read: &str, target: &str) -> bool {
    read == target || read == row_field_name(target) || row_field_name(read) == target
}

fn root_scalar_target_reads_changed_root(
    expression: &ScalarUpdateExpression,
    changed_reads: &BTreeSet<GenericReadKey>,
    derived_state: &GenericDerivedState,
    derived_plan: &GenericDerivedPlan,
) -> bool {
    if changed_reads.is_empty() {
        return false;
    }
    let read_paths = expression.same_event_root_read_paths();
    if read_paths.is_empty() {
        return false;
    }
    read_paths.into_iter().any(|read| {
        root_scalar_read_path_depends_on_changed_read(
            read,
            changed_reads,
            derived_state,
            derived_plan,
        )
    })
}

fn root_scalar_read_path_depends_on_changed_read(
    read: &str,
    changed_reads: &BTreeSet<GenericReadKey>,
    derived_state: &GenericDerivedState,
    derived_plan: &GenericDerivedPlan,
) -> bool {
    let mut visited = BTreeSet::new();
    root_scalar_read_path_candidates(read)
        .into_iter()
        .any(|field| {
            root_scalar_field_depends_on_changed_read(
                &field,
                changed_reads,
                derived_state,
                derived_plan,
                &mut visited,
            )
        })
}

fn root_scalar_read_path_candidates(read: &str) -> Vec<String> {
    if let Some(local) = read.strip_prefix("store.") {
        vec![read.to_owned(), local.to_owned()]
    } else {
        vec![read.to_owned(), format!("store.{read}")]
    }
}

fn root_scalar_field_depends_on_changed_read(
    field: &str,
    changed_reads: &BTreeSet<GenericReadKey>,
    derived_state: &GenericDerivedState,
    derived_plan: &GenericDerivedPlan,
    visited: &mut BTreeSet<String>,
) -> bool {
    let Some(plan) = derived_plan.root_field_plan_for_source_read_path(field) else {
        return false;
    };
    let canonical = plan.path.as_str();
    if !visited.insert(canonical.to_owned()) {
        return false;
    }
    let direct_read_changed = root_read_keys_for_path(field)
        .iter()
        .any(|read| changed_reads.contains(read))
        || root_read_keys_for_path(canonical)
            .iter()
            .any(|read| changed_reads.contains(read));
    if direct_read_changed && !plan.has_sources {
        return true;
    }
    let Some(reads) = derived_state.root_reads_by_field.get(canonical) else {
        return false;
    };
    if reads.iter().any(|read| changed_reads.contains(read)) {
        return true;
    }
    reads.iter().any(|read| {
        let GenericReadKey::Root { field: dependency } = read else {
            return false;
        };
        root_scalar_read_path_candidates(dependency)
            .into_iter()
            .any(|candidate| {
                root_scalar_field_depends_on_changed_read(
                    &candidate,
                    changed_reads,
                    derived_state,
                    derived_plan,
                    visited,
                )
            })
    })
}

fn update_value_expression_root_read_paths<'a>(
    expression: &'a UpdateValueExpression,
    reads: &mut Vec<&'a str>,
) {
    match expression {
        UpdateValueExpression::Const { .. } => {}
        UpdateValueExpression::ReadPath { path } => reads.push(path.as_str()),
        UpdateValueExpression::MatchConst { input, arms } => {
            reads.push(input.as_str());
            for arm in arms {
                update_value_expression_root_read_paths(&arm.output, reads);
            }
        }
        UpdateValueExpression::NumberInfix { left, right, .. } => {
            reads.push(left.as_str());
            reads.push(right.as_str());
        }
        UpdateValueExpression::MatchNumberInfixConst {
            left, right, arms, ..
        } => {
            reads.push(left.as_str());
            reads.push(right.as_str());
            for arm in arms {
                update_value_expression_root_read_paths(&arm.output, reads);
            }
        }
    }
}

fn root_read_keys_for_path(path: &str) -> Vec<GenericReadKey> {
    let mut keys = Vec::with_capacity(3);
    push_root_read_key_for_path_aliases(path, |field| {
        keys.push(GenericReadKey::Root {
            field: field.to_owned(),
        });
    });
    keys
}

fn push_root_read_key_for_path_aliases(path: &str, mut push: impl FnMut(&str)) {
    push(path);
    let leaf = row_field_name(path);
    if leaf != path {
        push(leaf);
    }
    if let Some(local) = path.strip_prefix("store.")
        && local != path
        && local != leaf
    {
        push(local);
    }
}

fn root_read_key_matches_path(read: &GenericReadKey, path: &str) -> bool {
    let GenericReadKey::Root { field } = read else {
        return false;
    };
    field == path
        || field == row_field_name(path)
        || path
            .strip_prefix("store.")
            .is_some_and(|local| field == local)
}

fn root_reads_include_path(reads: &BTreeSet<GenericReadKey>, path: &str) -> bool {
    reads
        .iter()
        .any(|read| root_read_key_matches_path(read, path))
}

fn root_dirty_read_key_counts(dirty: &BTreeSet<String>) -> BTreeMap<GenericReadKey, usize> {
    let mut counts = BTreeMap::new();
    for path in dirty {
        add_root_dirty_read_key_counts(&mut counts, path);
    }
    counts
}

fn add_root_dirty_read_key_counts(counts: &mut BTreeMap<GenericReadKey, usize>, path: &str) {
    push_root_read_key_for_path_aliases(path, |field| {
        let read = GenericReadKey::Root {
            field: field.to_owned(),
        };
        *counts.entry(read).or_insert(0) += 1;
    });
}

fn remove_root_dirty_read_key_counts(counts: &mut BTreeMap<GenericReadKey, usize>, path: &str) {
    push_root_read_key_for_path_aliases(path, |field| {
        let read = GenericReadKey::Root {
            field: field.to_owned(),
        };
        match counts.get_mut(&read) {
            Some(count) if *count > 1 => *count -= 1,
            Some(_) => {
                counts.remove(&read);
            }
            None => {}
        }
    });
}

fn root_read_keys_for_nested_path(path: &str) -> Vec<GenericReadKey> {
    let mut keys = BTreeSet::from([GenericReadKey::Root {
        field: path.to_owned(),
    }]);
    if let Some(local) = path.strip_prefix("store.") {
        keys.insert(GenericReadKey::Root {
            field: local.to_owned(),
        });
    }
    keys.into_iter().collect()
}

fn root_changed_read_keys_for_materialized_value(
    path: &str,
    value: &BoonValue,
    previous: Option<&FieldValue>,
) -> Vec<GenericReadKey> {
    let mut keys = root_read_keys_for_path(path)
        .into_iter()
        .collect::<BTreeSet<_>>();
    if let Some(FieldValue::Json(previous)) = previous {
        collect_changed_structured_child_read_keys(path, value, previous, &mut keys);
    } else {
        collect_boon_value_root_read_keys(path, value, &mut keys);
    }
    keys.into_iter().collect()
}

fn collect_changed_structured_child_read_keys(
    path: &str,
    value: &BoonValue,
    previous: &JsonValue,
    keys: &mut BTreeSet<GenericReadKey>,
) {
    match (value, previous) {
        (BoonValue::Record(fields), JsonValue::Object(previous_fields)) => {
            let field_names = fields
                .keys()
                .chain(previous_fields.keys())
                .cloned()
                .collect::<BTreeSet<_>>();
            for field in field_names {
                let child_path = format!("{path}.{field}");
                match (fields.get(&field), previous_fields.get(&field)) {
                    (Some(value), Some(previous)) => {
                        collect_changed_structured_child_read_keys(
                            &child_path,
                            value,
                            previous,
                            keys,
                        );
                    }
                    (Some(value), None) => {
                        keys.extend(root_read_keys_for_nested_path(&child_path));
                        collect_boon_value_root_read_keys(&child_path, value, keys);
                    }
                    (None, Some(previous)) => {
                        keys.extend(root_read_keys_for_nested_path(&child_path));
                        collect_json_root_read_keys(&child_path, previous, keys);
                    }
                    (None, None) => {}
                }
            }
        }
        (BoonValue::List(values), JsonValue::Array(previous_values)) => {
            let len = values.len().max(previous_values.len());
            for index in 0..len {
                let child_path = format!("{path}.{index}");
                match (values.get(index), previous_values.get(index)) {
                    (Some(value), Some(previous)) => {
                        collect_changed_structured_child_read_keys(
                            &child_path,
                            value,
                            previous,
                            keys,
                        );
                    }
                    (Some(value), None) => {
                        keys.extend(root_read_keys_for_nested_path(&child_path));
                        collect_boon_value_root_read_keys(&child_path, value, keys);
                    }
                    (None, Some(previous)) => {
                        keys.extend(root_read_keys_for_nested_path(&child_path));
                        collect_json_root_read_keys(&child_path, previous, keys);
                    }
                    (None, None) => {}
                }
            }
        }
        _ if boon_value_matches_json(value, previous) => {}
        _ => {
            keys.extend(root_read_keys_for_nested_path(path));
            collect_boon_value_root_read_keys(path, value, keys);
            collect_json_root_read_keys(path, previous, keys);
        }
    }
}

fn collect_boon_value_root_read_keys(
    path: &str,
    value: &BoonValue,
    keys: &mut BTreeSet<GenericReadKey>,
) {
    match value {
        BoonValue::Record(fields) => {
            for (field, value) in fields {
                let child_path = format!("{path}.{field}");
                keys.extend(root_read_keys_for_nested_path(&child_path));
                collect_boon_value_root_read_keys(&child_path, value, keys);
            }
        }
        BoonValue::RecordColumns(columns) => {
            collect_value_columns_root_read_keys(path, columns, keys);
        }
        BoonValue::List(values) => {
            for (index, value) in values.iter().enumerate() {
                let child_path = format!("{path}.{index}");
                keys.extend(root_read_keys_for_nested_path(&child_path));
                collect_boon_value_root_read_keys(&child_path, value, keys);
            }
        }
        BoonValue::Empty
        | BoonValue::Text(_)
        | BoonValue::Enum(_)
        | BoonValue::Number(_)
        | BoonValue::Bool(_)
        | BoonValue::RowRef { .. }
        | BoonValue::ListRef(_)
        | BoonValue::ListSelection { .. }
        | BoonValue::NaN
        | BoonValue::Error(_) => {}
    }
}

fn collect_json_root_read_keys(path: &str, value: &JsonValue, keys: &mut BTreeSet<GenericReadKey>) {
    match value {
        JsonValue::Object(fields) => {
            for (field, value) in fields {
                let child_path = format!("{path}.{field}");
                keys.extend(root_read_keys_for_nested_path(&child_path));
                collect_json_root_read_keys(&child_path, value, keys);
            }
        }
        JsonValue::Array(values) => {
            for (index, value) in values.iter().enumerate() {
                let child_path = format!("{path}.{index}");
                keys.extend(root_read_keys_for_nested_path(&child_path));
                collect_json_root_read_keys(&child_path, value, keys);
            }
        }
        JsonValue::Null | JsonValue::Bool(_) | JsonValue::Number(_) | JsonValue::String(_) => {}
    }
}

fn boon_value_matches_json(value: &BoonValue, previous: &JsonValue) -> bool {
    match (value, previous) {
        (BoonValue::Empty, JsonValue::Null) => true,
        (BoonValue::Bool(value), JsonValue::Bool(previous)) => value == previous,
        (BoonValue::Number(value), JsonValue::Number(previous)) => {
            previous.as_i64() == Some(*value)
        }
        (BoonValue::Text(value) | BoonValue::Enum(value), JsonValue::String(previous)) => {
            value == previous
        }
        (BoonValue::RecordColumns(columns), JsonValue::Object(_)) => {
            &value_columns_json(columns) == previous
        }
        (BoonValue::NaN, JsonValue::String(previous)) => previous == "NaN",
        (BoonValue::Error(value), JsonValue::String(previous)) => value == previous,
        (BoonValue::RowRef { list, index }, previous) => {
            previous == &json!({ "list": list, "index": index })
        }
        (BoonValue::ListRef(list), JsonValue::String(previous)) => list == previous,
        (BoonValue::ListSelection { list, indices }, previous) => {
            previous == &json!({ "list": list, "indices": indices })
        }
        _ => false,
    }
}

