impl SourceAction {
    fn kind_label(&self) -> &'static str {
        match self {
            Self::RootScalar => "root_scalar",
            Self::DerivedText { .. } => "derived_text",
            Self::RouterRoute { .. } => "router_route",
            Self::RootTextTransform { .. } => "root_text_transform",
            Self::ListRemove { .. } => "list_remove",
            Self::ListAppend { .. } => "list_append",
            Self::IndexedText { kind, .. } => kind.as_str(),
            Self::IndexedBool { kind, .. } => kind.as_str(),
        }
    }
}

