    #[test]
    fn source_text_payload_can_be_read_inside_then_update_expression() {
        let source = r#"
store: [
    elements: [
        path_input: SOURCE
    ]
    path:
        TEXT { default-path } |> HOLD path {
            LATEST {
                elements.path_input.text |> THEN { elements.path_input.text }
            }
        }
    label:
        TEXT { Path: } |> Text/concat(with: path, separator: " ")
]

document: Document/new(root: Element/label(element: [], label: store.path))
"#;
        let mut runtime =
            LiveRuntime::from_source("source-text-then-update-expression", source).unwrap();
        assert_eq!(
            runtime.document_state_summary().pointer("/store/path"),
            Some(&json!("default-path"))
        );
        assert_eq!(
            runtime.document_state_summary().pointer("/store/label"),
            Some(&json!("Path: default-path"))
        );
        runtime
            .apply_source_event(LiveSourceEvent {
                source: "store.elements.path_input".to_owned(),
                text: Some("/tmp/wave.vcd".to_owned()),
                ..LiveSourceEvent::default()
            })
            .unwrap();
        assert_eq!(
            runtime.document_state_summary().pointer("/store/path"),
            Some(&json!("/tmp/wave.vcd"))
        );

        let source_with_path_default =
            source.replace("default-path", "~/repos/NovyWave/test_files/simple.vcd");
        let mut runtime =
            LiveRuntime::from_source("source-text-path-default", &source_with_path_default)
                .unwrap();
        assert_eq!(
            runtime.document_state_summary().pointer("/store/path"),
            Some(&json!("~/repos/NovyWave/test_files/simple.vcd"))
        );
        assert_eq!(
            runtime.document_state_summary().pointer("/store/label"),
            Some(&json!("Path: ~/repos/NovyWave/test_files/simple.vcd"))
        );
    }

    #[test]
    fn source_payload_concat_inside_latest_updates_without_then_wrapper() {
        let source = r#"
store: [
    elements: [
        external_file_loaded_name: SOURCE
        show_empty: SOURCE
    ]
    external_file_tree_label:
        TEXT { - local file } |> HOLD external_file_tree_label {
            LATEST {
                TEXT { - } |> Text/concat(with: elements.external_file_loaded_name.text, separator: " ")
                elements.show_empty.event.press |> THEN { TEXT { - local file } }
            }
        }
]

document: Document/new(root: Element/label(element: [], label: store.external_file_tree_label))
"#;
        let mut runtime =
            LiveRuntime::from_source("source-payload-concat-latest-runtime", source).unwrap();
        assert_eq!(
            runtime
                .document_state_summary()
                .pointer("/store/external_file_tree_label"),
            Some(&json!("- local file"))
        );

        runtime
            .apply_source_event(LiveSourceEvent {
                source: "store.elements.external_file_loaded_name".to_owned(),
                text: Some("wave_27.fst".to_owned()),
                ..LiveSourceEvent::default()
            })
            .expect("source text payload should update direct concat branch");
        assert_eq!(
            runtime
                .document_state_summary()
                .pointer("/store/external_file_tree_label"),
            Some(&json!("- wave_27.fst"))
        );

        runtime
            .apply_source_event(LiveSourceEvent {
                source: "store.elements.show_empty".to_owned(),
                ..LiveSourceEvent::default()
            })
            .expect("reset source should update THEN branch");
        assert_eq!(
            runtime
                .document_state_summary()
                .pointer("/store/external_file_tree_label"),
            Some(&json!("- local file"))
        );
    }

    #[test]
