    #[test]
    fn root_list_view_row_field_diff_skips_structure_only_dependents() {
        let source = r#"
store: [
    elements: [
        click: SOURCE
    ]
    dummy:
        TEXT { idle } |> HOLD dummy {
            LATEST {
                elements.click.event.press |> THEN { TEXT { clicked } }
            }
        }
    signals:
        LIST {
            [id: TEXT { a }, name: TEXT { A }, label: TEXT { middle }]
        }
    rows:
        signals |> List/map(signal, new: [
            id: signal.id
            label: signal.label
        ])
]

document: Document/new(root: Element/label(element: [], label: TEXT { ok }))
"#;
        let runtime = LiveRuntime::from_source("root-list-view-row-field-diff", source).unwrap();
        let generic = runtime
            .runtime
            .generic
            .expect("test runtime should use generic engine");
        let row = |id: &str, label: &str| {
            let mut columns = ValueColumns::default();
            columns.insert_value("id".to_owned(), FieldValue::Text(id.to_owned()));
            columns.insert_value("label".to_owned(), FieldValue::Text(label.to_owned()));
            RuntimeRowSnapshot { columns }
        };
        let previous = vec![row("a", "middle")];
        let current = vec![row("a", "new")];
        let reads =
            generic.root_list_view_changed_read_keys("store.rows", "rows", &previous, &current);
        let mut expected = BTreeSet::new();
        insert_changed_list_field_read_keys(&mut expected, "rows", 0, "label");
        assert_eq!(
            reads, expected,
            "row-field changes should dirty only the exact row field"
        );

        let row_with_extra = |id: &str, label: &str, extra: &str| {
            let mut columns = ValueColumns::default();
            columns.insert_value("id".to_owned(), FieldValue::Text(id.to_owned()));
            columns.insert_value("label".to_owned(), FieldValue::Text(label.to_owned()));
            columns.insert_value("extra".to_owned(), FieldValue::Text(extra.to_owned()));
            RuntimeRowSnapshot { columns }
        };
        let previous_shape = vec![row_with_extra("a", "middle", "x")];
        let current_shape = vec![row("a", "middle")];
        let shape_change = generic.root_list_view_changed_reads(
            "store.rows",
            "rows",
            &previous_shape,
            &current_shape,
        );
        let mut expected_shape = BTreeSet::new();
        insert_changed_list_field_read_keys(&mut expected_shape, "rows", 0, "extra");
        assert_eq!(
            shape_change.changed_reads, expected_shape,
            "same-length row-shape changes should dirty only added/removed row fields"
        );
        assert_eq!(shape_change.changed_row_count, 1);
        assert_eq!(shape_change.changed_field_count, 1);
        assert!(
            !shape_change.broad_fallback,
            "same-length row-shape changes are field changes, not list structure changes"
        );

        let broad = generic.root_list_view_changed_read_keys("store.rows", "rows", &previous, &[]);
        assert!(
            broad.contains(&list_read_key("rows"))
                && broad.contains(&GenericReadKey::Root {
                    field: "store.rows".to_owned()
                })
                && broad.contains(&GenericReadKey::Root {
                    field: "rows".to_owned()
                }),
            "length changes must fall back to broad structure/root invalidation: {broad:?}"
        );
    }

