        let step = &output.report["per_step_pass_fail"][0];
        assert_eq!(step["list_delta_operator_hits"], json!(2));
        assert_eq!(step["list_delta_operator_fallbacks"], json!(0));
        assert_eq!(step["list_delta_oracle_checks"], json!(2));
