    #[test]
    fn list_delta_large_count_operator_matches_full_scan_oracle() {
        let rows = (0..1000)
            .map(|index| {
                let completed = if index % 2 == 0 { "False" } else { "True" };
                format!("[title: TEXT {{ Item {index} }}, completed: {completed}]")
            })
            .collect::<Vec<_>>()
            .join("\n            ");
        let source = include_str!("../../../examples/todomvc.bn").replace(
            "[title: TEXT { Read documentation }, completed: False]\n            [title: TEXT { Finish TodoMVC renderer }, completed: True]\n            [title: TEXT { Walk the dog }, completed: False]\n            [title: TEXT { Buy groceries }, completed: False]",
            &rows,
        );
        let parsed = parse_source("large-todomvc-count-delta.bn", source).unwrap();
        let ir = lower(&parsed).unwrap();
        let compiled = CompiledProgram::from_ir(&ir).unwrap();
        let mut runtime = LoadedRuntime::new(&ir, &compiled).unwrap();
        let mut deltas = Vec::new();
        let mut patches = Vec::new();
        let step = LiveSourceEvent {
            source: "todo.sources.todo_checkbox.click".to_owned(),
            target_text: Some("Item 500".to_owned()),
            ..LiveSourceEvent::default()
        }
        .into_step(1);

        let metrics = runtime
            .apply_step(&step, &mut deltas, &mut patches)
            .unwrap();
        let counters = metrics.list_delta_counters();
        let generic = runtime.generic.as_ref().unwrap();

        assert_eq!(counters.operator_hits, 2);
        assert_eq!(counters.affected_rows, 2);
        assert_eq!(counters.oracle_checks, 2);
        assert_eq!(counters.oracle_mismatches, 0);
        assert_eq!(
            generic
                .count_list_rows_for_target("todos", "store.active_count")
                .unwrap(),
            499
        );
        assert_eq!(
            generic
                .count_list_rows_for_target("todos", "store.completed_count")
                .unwrap(),
            501
        );
        assert_eq!(
            generic
                .count_list_rows_for_target("todos", "store.active_count")
                .unwrap(),
            generic
                .count_list_rows_for_target_full_scan("todos", "store.active_count")
                .unwrap()
        );
        assert_eq!(
            generic
                .count_list_rows_for_target("todos", "store.completed_count")
                .unwrap(),
            generic
                .count_list_rows_for_target_full_scan("todos", "store.completed_count")
                .unwrap()
        );
    }

